srcDoc.js:
function showError(msg) {
  var el = document.getElementById('error_msg');
  if (el) el.textContent = msg || '';
}
function showChangePwError(msg) {
  var el = document.getElementById('change_pw_error');
  if (el) el.textContent = msg || '';
}
function setSignInBusy(busy) {
  var btn = document.getElementById('signin_btn');
  if (btn) {
    btn.textContent = busy ? 'Signing in…' : 'Sign in';
    btn.disabled = busy;
  }
}
function showChangePasswordView() {
  document.getElementById('login_view').style.display = 'none';
  document.getElementById('change_pw_view').style.display = 'block';
}
function handleSignIn() {
  var email = document.getElementById('email').value.trim();
  var password = document.getElementById('password').value;
  showError('');
  if (!email || !password) {
    showError('Please enter your email and password.');
    return;
  }
  if (email.toLowerCase().split('@')[1] !== 'mbhglobal.co.uk') {
    showError('Access is restricted to @mbhglobal.co.uk accounts.');
    return;
  }
  setSignInBusy(true);
  appsmith.updateModel({
    loginEmail: email,
    loginPassword: password
  });
  appsmith.triggerEvent('onLoginSubmit');
}
function handleSavePassword() {
  var pw = document.getElementById('new_password').value;
  var confirm = document.getElementById('confirm_password').value;
  showChangePwError('');
  if (!pw || pw.length < 8) {
    showChangePwError('Password must be at least 8 characters.');
    return;
  }
  if (pw !== confirm) {
    showChangePwError('Passwords do not match.');
    return;
  }
  appsmith.updateModel({
    newPassword: pw
  });
  appsmith.triggerEvent('onSetNewPassword');
}
function render(model) {
  var m = model || {};
  if (m.loginErrorMessage !== undefined) {
    showError(m.loginErrorMessage);
    setSignInBusy(false);
  }
  if (m.changePwErrorMessage !== undefined) {
    showChangePwError(m.changePwErrorMessage);
  }
  if (m.requirePasswordChange) {
    showChangePasswordView();
  }
}
function initWhenReady() {
  if (typeof appsmith === 'undefined' || !appsmith.onReady) {
    setTimeout(initWhenReady, 50);
    return;
  }
  appsmith.onReady(function () {
    var signinBtn = document.getElementById('signin_btn');
    if (signinBtn) signinBtn.addEventListener('click', handleSignIn);
    var savePwBtn = document.getElementById('save_pw_btn');
    if (savePwBtn) savePwBtn.addEventListener('click', handleSavePassword);
    document.addEventListener('keydown', function (e) {
      if (e.key !== 'Enter') return;
      var active = document.activeElement;
      if (active && (active.id === 'email' || active.id === 'password')) handleSignIn();
      if (active && (active.id === 'new_password' || active.id === 'confirm_password')) handleSavePassword();
    });
    render(appsmith.model);
    appsmith.onModelChange(function (model) {
      render(model);
    });
  });
}
initWhenReady();

